# Gerado a partir de spark/sql/ (pasta sql removida; conteúdo embutido para paridade com dbt).

PIPELINE_SQL = "-- Grain: 1 linha = 1 código de procedimento (deduplicado por cd_procedimento)\n-- Fonte: silver_context.procedimento via glue_catalog.silver_context.procedimento\n-- Camada: Gold | Tipo: SCD1 (códigos de procedimento são estáveis)\n-- Dimensão conformada — compartilhada entre fatos assistenciais e financeiros\n\n\nWITH source AS (\n    SELECT * FROM glue_catalog.silver_context.procedimento\n    WHERE cd_procedimento <> -1\n)\n\n-- Pega o estado mais recente de cada procedimento via _context_processed_at\n, proc_ranked AS (\n    SELECT\n        cd_procedimento\n      , ds_procedimento\n      , cd_grupo\n      , cd_tabela_servico\n      , cd_tabela_custo\n      , ROW_NUMBER() OVER (\n            PARTITION BY cd_procedimento\n            ORDER BY _context_processed_at DESC\n        ) AS rn\n    FROM source\n)\n\n, final AS (\n    SELECT\n          md5(concat_ws('||', coalesce(cast(cd_procedimento as string), '_dbt_utils_surrogate_key_null_')))  AS sk_procedimento\n        , cd_procedimento                                              AS nk_procedimento\n        , ds_procedimento\n        , cd_grupo\n        , cd_tabela_servico\n        , cd_tabela_custo\n        , FROM_UTC_TIMESTAMP(CURRENT_TIMESTAMP(), 'America/Sao_Paulo') AS _gold_loaded_at\n    FROM proc_ranked\n    WHERE rn = 1\n)\n\nSELECT * FROM final\n"
